import java.util.*;

class Solution {
    // Function to compute subset sums using bitmasking
    public List<Integer> subsetSums(int[] arr) {
        int n = arr.length;
        List<Integer> sums = new ArrayList<>();

        // Loop through all possible subsets represented by bitmasks
        for (int mask = 0; mask < (1 << n); mask++) {
            int sum = 0; // sum of current subset
            // Check each bit in the mask
            for (int i = 0; i < n; i++) {
                // If the i-th bit is set, include arr[i] in sum
                if ((mask & (1 << i)) != 0) {
                    sum += arr[i];
                }
            }
            sums.add(sum); // store sum
        }

        // Sort sums in increasing order
        Collections.sort(sums);
        return sums;
    }
}

public class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        int[] arr = {5, 2, 1};
        List<Integer> result = sol.subsetSums(arr);

        for (int sum : result) {
            System.out.print(sum + " ");
        }
        System.out.println();
    }
}

